external_knowledge:
- "Best-selling products" refers to products with the highest total quantity sold; 
- The ranking is determined by the total quantity sold in descending order, meaning the product with the most quantity sold is ranked #1;
- "Top 3 performing products" refers to products with a rank of 3 or less in their respective regions;
- The sales quantity and revenue are aggregated by product and region.

sql:
SELECT product_id, COUNT(*) AS alert_count
FROM low_stock_alerts
GROUP BY product_id;

SELECT product_id
FROM low_stock_alerts
ORDER BY alert_date DESC;

SELECT SUM(quantity) AS total_reorder_quantity, MAX(reorder_date) AS latest_reorder_date
FROM reorders
WHERE product_id = 1;
